"use client"

import * as React from "react"
import { Calendar } from "@/components/ui/calendar"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { cn } from "@/lib/utils"
import { TIME_SLOTS } from "@/lib/booking-constants"
import { IconCalendar, IconCalendarEvent, IconClock, IconClipboardList } from "@tabler/icons-react"
import { BookingType } from "@/lib/schemas"
import { isDateBooked, isDateInPast, isTimeDisabled, isTimeInRange, getSlotIndex, hasTimeConflict } from "@/lib/booking-utils"
import { startOfDay } from "date-fns"

interface BookingCalendarProps {
  date: Date | undefined
  startTime: string | null
  endTime: string | null
  bookingType: BookingType
  bookedSlots: string[]
  fullyBookedDates: Date[]
  onDateChange: (date: Date | undefined) => void
  onStartTimeChange: (time: string | null) => void
  onEndTimeChange: (time: string | null) => void
  onBookingTypeChange: (type: BookingType) => void
}

export function BookingCalendar({
  date,
  startTime,
  endTime,
  bookingType,
  bookedSlots,
  fullyBookedDates,
  onDateChange,
  onStartTimeChange,
  onEndTimeChange,
  onBookingTypeChange,
}: BookingCalendarProps) {

  const handleDateSelect = (newDate: Date | undefined) => {
    onDateChange(newDate)
    onStartTimeChange(null)
    onEndTimeChange(null)
  }

  const handleTimeClick = (slot: string) => {
    if (!startTime) {
      onStartTimeChange(slot)
      onEndTimeChange(null)
      return
    }
    if (slot === startTime) {
      onStartTimeChange(null)
      onEndTimeChange(null)
      return
    }
    const clickedIdx = getSlotIndex(slot)
    const startIdx = getSlotIndex(startTime)
    if (clickedIdx < startIdx) {
      onStartTimeChange(slot)
      onEndTimeChange(null)
      return
    }
    if (hasTimeConflict(startTime, slot, bookedSlots)) return
    onEndTimeChange(slot)
  }

  return (
    <div className="flex w-full flex-col gap-4 md:flex-row md:items-stretch">
      {/* Calendar Card */}
      <Card className="flex flex-col gap-2 md:flex-[5]">
        <CardHeader className="pb-2">
          <CardTitle className="flex items-center gap-2">
            <IconCalendar className="size-4 text-blue-500" />
            <span className="bg-gradient-to-r from-[#3F51B5] via-[#3A79C3] to-[#329A9A] bg-clip-text text-base font-bold text-transparent">
              Pick a date
            </span>
          </CardTitle>
          <CardDescription>Select your preferred appointment date.</CardDescription>
        </CardHeader>
        <CardContent className="flex flex-1 flex-col justify-between gap-2">
          <Calendar
            mode="single"
            selected={date}
            onSelect={handleDateSelect}
            captionLayout="dropdown"
            disabled={(d) => isDateInPast(d)}
            className="w-full flex-1 [--cell-size:--spacing(10)] [&_button[data-selected-single=true]]:bg-[#3A79C3] [&_button[data-selected-single=true]]:text-white [&_button[data-selected-single=true]]:hover:bg-[#3164a8]"
            classNames={{ root: "w-full" }}
            modifiers={{
              booked: fullyBookedDates,
              available: (d) => !isDateInPast(d) && !isDateBooked(d, fullyBookedDates),
            }}
            modifiersClassNames={{
              available: "[&_button]:bg-green-50 [&_button]:text-green-800 [&_button:hover]:bg-green-100",
              booked: "[&_button]:!bg-red-100 [&_button]:!text-red-600 [&_button:hover]:!bg-red-200 [&_button]:cursor-not-allowed [&_button]:pointer-events-none",
              disabled: "[&_button]:!bg-transparent !text-muted-foreground !opacity-40",
            }}
            formatters={{
              formatMonthDropdown: (d) =>
                d.toLocaleString("default", { month: "long" }),
            }}
          />
          <div className="flex items-center justify-center gap-4 pt-1 text-xs text-muted-foreground">
            <span className="flex items-center gap-1.5">
              <span className="inline-block shrink-0 size-3 rounded-sm bg-green-100 ring-1 ring-green-400" />
              Available
            </span>
            <span className="flex items-center gap-1.5">
              <span className="inline-block shrink-0 size-3 rounded-sm bg-red-100 ring-1 ring-red-400" />
              Fully Booked
            </span>
            <span className="flex items-center gap-1.5">
              <span className="inline-block shrink-0 size-3 rounded-sm bg-muted ring-1 ring-border" />
              Unavailable
            </span>
          </div>
        </CardContent>
      </Card>

      {/* Right column: time + booking type */}
      <div className="flex flex-col gap-4 md:flex-[3]">
        {/* Time Range Card */}
        <Card className="flex flex-1 flex-col gap-2">
          <CardHeader className="pb-2">
            <CardTitle className="flex items-center gap-2">
              <IconClock className="size-4 text-blue-500" />
              <span className="bg-gradient-to-r from-[#3F51B5] via-[#3A79C3] to-[#329A9A] bg-clip-text text-base font-bold text-transparent">
                Pick a time
              </span>
              {date && (
                <span className="ml-auto text-xs font-normal text-muted-foreground">
                  {date.toLocaleDateString("default", { weekday: "short", month: "short", day: "numeric" })}
                </span>
              )}
            </CardTitle>
            <CardDescription>Choose a start and end time for your slot.</CardDescription>
          </CardHeader>
          <CardContent className="flex flex-1 flex-col gap-2">
            {(startTime || endTime) && (
              <p className="text-xs text-[#3A79C3]">
                {startTime && !endTime && <>Start: <strong>{startTime}</strong> ΓÇö pick an end time</>}
                {startTime && endTime && <>Selected: <strong>{startTime}</strong> ΓåÆ <strong>{endTime}</strong></>}
              </p>
            )}
            <div className="flex-1">
              <div className="grid grid-cols-2 gap-2 h-full">
                {TIME_SLOTS.map((slot) => {
                  const isStart = startTime === slot
                  const isEnd = endTime === slot
                  const inRange = isTimeInRange(slot, startTime, endTime)
                  const disabled = isTimeDisabled(slot, startTime, endTime, bookedSlots)
                  return (
                    <button
                      key={slot}
                      disabled={disabled}
                      aria-pressed={isStart || isEnd}
                      onClick={() => handleTimeClick(slot)}
                      className={cn(
                        "rounded-md border px-3 py-2 text-sm font-medium transition-all",
                        disabled
                          ? "cursor-not-allowed border-border bg-muted text-muted-foreground line-through opacity-50"
                          : isStart || isEnd
                            ? "border-[#3A79C3] bg-[#3A79C3] text-white ring-1 ring-[#3A79C3]"
                            : inRange
                              ? "border-[#3A79C3]/40 bg-[#3A79C3]/10 text-[#3A79C3]"
                              : "border-border hover:border-[#3A79C3] hover:bg-[#3A79C3]/5"
                      )}
                    >
                      {slot}
                      {bookedSlots.includes(slot) && (
                        <Badge variant="outline" className="ml-1.5 border-red-300 px-1 py-0 text-[10px] text-red-400">
                          Full
                        </Badge>
                      )}
                    </button>
                  )
                })}
              </div>
            </div>
            <div className="flex flex-wrap items-center justify-center gap-4 pt-1 text-xs text-muted-foreground">
              <span className="flex items-center gap-1.5">
                <span className="inline-block shrink-0 size-3 rounded-sm bg-background ring-1 ring-border" />
                Available
              </span>
              <span className="flex items-center gap-1.5">
                <span className="inline-block shrink-0 size-3 rounded-sm bg-[#3A79C3] ring-1 ring-[#3A79C3]" />
                Selected
              </span>
              <span className="flex items-center gap-1.5">
                <span className="inline-block shrink-0 size-3 rounded-sm bg-muted ring-1 ring-border opacity-50" />
                Unavailable / Full
              </span>
            </div>
          </CardContent>
        </Card>

        {/* Booking Type Card */}
        <Card className="gap-2">
          <CardHeader className="pb-2">
            <CardTitle className="flex items-center gap-2">
              <IconCalendarEvent className="size-4 text-blue-500" />
              <span className="bg-gradient-to-r from-[#3F51B5] via-[#3A79C3] to-[#329A9A] bg-clip-text text-base font-bold text-transparent">
                Booking Type
              </span>
            </CardTitle>
            <CardDescription>Select whether this is an appointment or a reservation.</CardDescription>
          </CardHeader>
          <CardContent>
            <div className="grid grid-cols-2 gap-2">
              {(["Appointment", "Reservation"] as const).map((type) => {
                const Icon = type === "Appointment" ? IconCalendarEvent : IconClipboardList
                return (
                  <button
                    key={type}
                    onClick={() => onBookingTypeChange(type)}
                    className={cn(
                      "flex items-center justify-center gap-2 rounded-md border px-3 py-2 text-sm font-medium transition-all",
                      bookingType === type
                        ? "border-[#3A79C3] bg-[#3A79C3] text-white ring-1 ring-[#3A79C3]"
                        : "border-border hover:border-[#3A79C3] hover:bg-[#3A79C3]/5"
                    )}
                  >
                    <Icon className="size-4" />
                    {type}
                  </button>
                )
              })}
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  )
}

"use client"

import * as React from "react"
import { Label, Pie, PieChart } from "recharts"
import { IconChartBar, IconChartPie } from "@tabler/icons-react"
import {
  Card,
  CardContent,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import {
  ChartContainer,
  ChartTooltip,
  ChartTooltipContent,
  ChartLegend,
  ChartLegendContent,
  type ChartConfig,
} from "@/components/ui/chart"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"

export const description = "A donut chart with text"

const allChartData: Record<string, { status: string; count: number; fill: string }[]> = {
  reservation: [
    { status: "pending", count: 3, fill: "var(--color-pending)" },
    { status: "cancelled", count: 1, fill: "var(--color-cancelled)" },
    { status: "completed", count: 11, fill: "var(--color-completed)" },
  ],
  appointment: [
    { status: "pending", count: 5, fill: "var(--color-pending)" },
    { status: "cancelled", count: 2, fill: "var(--color-cancelled)" },
    { status: "completed", count: 8, fill: "var(--color-completed)" },
  ],
}

const chartConfig = {
  count: {
    label: "Bookings",
  },
  pending: {
    label: "Pending",
    color: "var(--chart-1)",
  },
  cancelled: {
    label: "Cancelled",
    color: "var(--chart-2)",
  },
  completed: {
    label: "Completed",
    color: "var(--chart-3)",
  },
} satisfies ChartConfig

export function ChartPie() {
  const [filter, setFilter] = React.useState<"reservation" | "appointment">("reservation")

  const chartData = allChartData[filter]

  const totalBookings = React.useMemo(() => {
    return chartData.reduce((acc, curr) => acc + curr.count, 0)
  }, [chartData])

  return (
    <Card className="flex h-[400px] flex-col">
      <CardHeader className="flex flex-row items-center justify-between pb-0">
        <CardTitle className="flex items-center gap-2">
          <IconChartPie className="size-4 text-blue-500" />
          <h1 className="bg-gradient-to-r from-[#3F51B5] via-[#3A79C3] to-[#329A9A] bg-clip-text text-base font-bold text-transparent">Distribution</h1>
        </CardTitle>
        <Select value={filter} onValueChange={(v) => setFilter(v as "reservation" | "appointment")}>
          <SelectTrigger className="h-8 w-[140px] text-xs">
            <SelectValue />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="reservation">
              <span className="flex items-center gap-2">
                <span className="size-2 rounded-[2px]" style={{ backgroundColor: "var(--chart-1)" }} />
                Reservation
              </span>
            </SelectItem>
            <SelectItem value="appointment">
              <span className="flex items-center gap-2">
                <span className="size-2 rounded-[2px]" style={{ backgroundColor: "var(--chart-2)" }} />
                Appointment
              </span>
            </SelectItem>
          </SelectContent>
        </Select>
      </CardHeader>
      <CardContent className="flex-1 pb-0">
        <ChartContainer
          config={chartConfig}
          className="h-[300px] w-full"
        >
          <PieChart>
            <ChartTooltip
              cursor={false}
              content={<ChartTooltipContent hideLabel />}
            />
            <ChartLegend content={<ChartLegendContent />} />
            <Pie
              data={chartData}
              dataKey="count"
              nameKey="status"
              innerRadius={60}
              strokeWidth={5}
            >
              <Label
                content={({ viewBox }) => {
                  if (viewBox && "cx" in viewBox && "cy" in viewBox) {
                    return (
                      <text
                        x={viewBox.cx}
                        y={viewBox.cy}
                        textAnchor="middle"
                        dominantBaseline="middle"
                      >
                        <tspan
                          x={viewBox.cx}
                          y={viewBox.cy}
                          className="fill-foreground text-3xl font-bold"
                        >
                          {totalBookings.toLocaleString()}
                        </tspan>
                        <tspan
                          x={viewBox.cx}
                          y={(viewBox.cy || 0) + 24}
                          className="fill-muted-foreground"
                        >
                          Bookings
                        </tspan>
                      </text>
                    )
                  }
                }}
              />
            </Pie>
          </PieChart>
        </ChartContainer>
      </CardContent>
    </Card>
  )
}

"use client"

import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"
import { PanelLeftIcon } from "lucide-react"
import { Slot } from "radix-ui"

import { useIsMobile } from "@/hooks/use-mobile"
import { cn } from "@/lib/utils"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Separator } from "@/components/ui/separator"
import {
  Sheet,
  SheetContent,
  SheetDescription,
  SheetHeader,
  SheetTitle,
} from "@/components/ui/sheet"
import { Skeleton } from "@/components/ui/skeleton"
import {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from "@/components/ui/tooltip"

const SIDEBAR_COOKIE_NAME = "sidebar_state"
const SIDEBAR_COOKIE_MAX_AGE = 60 * 60 * 24 * 7
const SIDEBAR_WIDTH = "16rem"
const SIDEBAR_WIDTH_MOBILE = "18rem"
const SIDEBAR_WIDTH_ICON = "3rem"
const SIDEBAR_KEYBOARD_SHORTCUT = "b"

type SidebarContextProps = {
  state: "expanded" | "collapsed"
  open: boolean
  setOpen: (open: boolean) => void
  openMobile: boolean
  setOpenMobile: (open: boolean) => void
  isMobile: boolean
  toggleSidebar: () => void
}

const SidebarContext = React.createContext<SidebarContextProps | null>(null)

function useSidebar() {
  const context = React.useContext(SidebarContext)
  if (!context) {
    throw new Error("useSidebar must be used within a SidebarProvider.")
  }

  return context
}

function SidebarProvider({
  defaultOpen = true,
  open: openProp,
  onOpenChange: setOpenProp,
  className,
  style,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  defaultOpen?: boolean
  open?: boolean
  onOpenChange?: (open: boolean) => void
}) {
  const isMobile = useIsMobile()
  const [openMobile, setOpenMobile] = React.useState(false)

  // This is the internal state of the sidebar.
  // We use openProp and setOpenProp for control from outside the component.
  const [_open, _setOpen] = React.useState(defaultOpen)
  const open = openProp ?? _open
  const setOpen = React.useCallback(
    (value: boolean | ((value: boolean) => boolean)) => {
      const openState = typeof value === "function" ? value(open) : value
      if (setOpenProp) {
        setOpenProp(openState)
      } else {
        _setOpen(openState)
      }

      // This sets the cookie to keep the sidebar state.
      document.cookie = `${SIDEBAR_COOKIE_NAME}=${openState}; path=/; max-age=${SIDEBAR_COOKIE_MAX_AGE}`
    },
    [setOpenProp, open]
  )

  // Helper to toggle the sidebar.
  const toggleSidebar = React.useCallback(() => {
    return isMobile ? setOpenMobile((open) => !open) : setOpen((open) => !open)
  }, [isMobile, setOpen, setOpenMobile])

  // Adds a keyboard shortcut to toggle the sidebar.
  React.useEffect(() => {
    const handleKeyDown = (event: KeyboardEvent) => {
      if (
        event.key === SIDEBAR_KEYBOARD_SHORTCUT &&
        (event.metaKey || event.ctrlKey)
      ) {
        event.preventDefault()
        toggleSidebar()
      }
    }

    window.addEventListener("keydown", handleKeyDown)
    return () => window.removeEventListener("keydown", handleKeyDown)
  }, [toggleSidebar])

  // We add a state so that we can do data-state="expanded" or "collapsed".
  // This makes it easier to style the sidebar with Tailwind classes.
  const state = open ? "expanded" : "collapsed"

  const contextValue = React.useMemo<SidebarContextProps>(
    () => ({
      state,
      open,
      setOpen,
      isMobile,
      openMobile,
      setOpenMobile,
      toggleSidebar,
    }),
    [state, open, setOpen, isMobile, openMobile, setOpenMobile, toggleSidebar]
  )

  return (
    <SidebarContext.Provider value={contextValue}>
      <TooltipProvider delayDuration={0}>
        <div
          data-slot="sidebar-wrapper"
          style={
            {
              "--sidebar-width": SIDEBAR_WIDTH,
              "--sidebar-width-icon": SIDEBAR_WIDTH_ICON,
              ...style,
            } as React.CSSProperties
          }
          className={cn(
            "group/sidebar-wrapper has-data-[variant=inset]:bg-sidebar flex min-h-svh w-full",
            className
          )}
          {...props}
        >
          {children}
        </div>
      </TooltipProvider>
    </SidebarContext.Provider>
  )
}

function Sidebar({
  side = "left",
  variant = "sidebar",
  collapsible = "offcanvas",
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  side?: "left" | "right"
  variant?: "sidebar" | "floating" | "inset"
  collapsible?: "offcanvas" | "icon" | "none"
}) {
  const { isMobile, state, openMobile, setOpenMobile } = useSidebar()

  if (collapsible === "none") {
    return (
      <div
        data-slot="sidebar"
        className={cn(
          "bg-sidebar text-sidebar-foreground flex h-full w-(--sidebar-width) flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    )
  }

  if (isMobile) {
    return (
      <Sheet open={openMobile} onOpenChange={setOpenMobile} {...props}>
        <SheetContent
          data-sidebar="sidebar"
          data-slot="sidebar"
          data-mobile="true"
          className="bg-sidebar text-sidebar-foreground w-(--sidebar-width) p-0 [&>button]:hidden"
          style={
            {
              "--sidebar-width": SIDEBAR_WIDTH_MOBILE,
            } as React.CSSProperties
          }
          side={side}
        >
          <SheetHeader className="sr-only">
            <SheetTitle>Sidebar</SheetTitle>
            <SheetDescription>Displays the mobile sidebar.</SheetDescription>
          </SheetHeader>
          <div className="flex h-full w-full flex-col">{children}</div>
        </SheetContent>
      </Sheet>
    )
  }

  return (
    <div
      className="group peer text-sidebar-foreground hidden md:block"
      data-state={state}
      data-collapsible={state === "collapsed" ? collapsible : ""}
      data-variant={variant}
      data-side={side}
      data-slot="sidebar"
    >
      {/* This is what handles the sidebar gap on desktop */}
      <div
        data-slot="sidebar-gap"
        className={cn(
          "relative w-(--sidebar-width) bg-transparent transition-[width] duration-200 ease-linear",
          "group-data-[collapsible=offcanvas]:w-0",
          "group-data-[side=right]:rotate-180",
          variant === "floating" || variant === "inset"
            ? "group-data-[collapsible=icon]:w-[calc(var(--sidebar-width-icon)+(--spacing(4)))]"
            : "group-data-[collapsible=icon]:w-(--sidebar-width-icon)"
        )}
      />
      <div
        data-slot="sidebar-container"
        className={cn(
          "fixed inset-y-0 z-10 hidden h-svh w-(--sidebar-width) transition-[left,right,width] duration-200 ease-linear md:flex",
          side === "left"
            ? "left-0 group-data-[collapsible=offcanvas]:left-[calc(var(--sidebar-width)*-1)]"
            : "right-0 group-data-[collapsible=offcanvas]:right-[calc(var(--sidebar-width)*-1)]",
          // Adjust the padding for floating and inset variants.
          variant === "floating" || variant === "inset"
            ? "p-2 group-data-[collapsible=icon]:w-[calc(var(--sidebar-width-icon)+(--spacing(4))+2px)]"
            : "group-data-[collapsible=icon]:w-(--sidebar-width-icon) group-data-[side=left]:border-r group-data-[side=right]:border-l",
          className
        )}
        {...props}
      >
        <div
          data-sidebar="sidebar"
          data-slot="sidebar-inner"
          className="bg-sidebar group-data-[variant=floating]:border-sidebar-border flex h-full w-full flex-col group-data-[variant=floating]:rounded-lg group-data-[variant=floating]:border group-data-[variant=floating]:shadow-sm"
        >
          {children}
        </div>
      </div>
    </div>
  )
}

function SidebarTrigger({
  className,
  onClick,
  ...props
}: React.ComponentProps<typeof Button>) {
  const { toggleSidebar } = useSidebar()

  return (
    <Button
      data-sidebar="trigger"
      data-slot="sidebar-trigger"
      variant="ghost"
      size="icon"
      className={cn("size-7", className)}
      onClick={(event) => {
        onClick?.(event)
        toggleSidebar()
      }}
      {...props}
    >
      <PanelLeftIcon />
      <span className="sr-only">Toggle Sidebar</span>
    </Button>
  )
}

function SidebarRail({ className, ...props }: React.ComponentProps<"button">) {
  const { toggleSidebar } = useSidebar()

  return (
    <button
      data-sidebar="rail"
      data-slot="sidebar-rail"
      aria-label="Toggle Sidebar"
      tabIndex={-1}
      onClick={toggleSidebar}
      title="Toggle Sidebar"
      className={cn(
        "hover:after:bg-sidebar-border absolute inset-y-0 z-20 hidden w-4 -translate-x-1/2 transition-all ease-linear group-data-[side=left]:-right-4 group-data-[side=right]:left-0 after:absolute after:inset-y-0 after:left-1/2 after:w-[2px] sm:flex",
        "in-data-[side=left]:cursor-w-resize in-data-[side=right]:cursor-e-resize",
        "[[data-side=left][data-state=collapsed]_&]:cursor-e-resize [[data-side=right][data-state=collapsed]_&]:cursor-w-resize",
        "hover:group-data-[collapsible=offcanvas]:bg-sidebar group-data-[collapsible=offcanvas]:translate-x-0 group-data-[collapsible=offcanvas]:after:left-full",
        "[[data-side=left][data-collapsible=offcanvas]_&]:-right-2",
        "[[data-side=right][data-collapsible=offcanvas]_&]:-left-2",
        className
      )}
      {...props}
    />
  )
}

function SidebarInset({ className, ...props }: React.ComponentProps<"main">) {
  return (
    <main
      data-slot="sidebar-inset"
      className={cn(
        "bg-background relative flex w-full flex-1 flex-col",
        "md:peer-data-[variant=inset]:m-2 md:peer-data-[variant=inset]:ml-0 md:peer-data-[variant=inset]:rounded-xl md:peer-data-[variant=inset]:shadow-sm md:peer-data-[variant=inset]:peer-data-[state=collapsed]:ml-2",
        className
      )}
      {...props}
    />
  )
}

function SidebarInput({
  className,
  ...props
}: React.ComponentProps<typeof Input>) {
  return (
    <Input
      data-slot="sidebar-input"
      data-sidebar="input"
      className={cn("bg-background h-8 w-full shadow-none", className)}
      {...props}
    />
  )
}

function SidebarHeader({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="sidebar-header"
      data-sidebar="header"
      className={cn("flex flex-col gap-2 p-2", className)}
