export function UpcomingTable({ bookings }: UpcomingTableProps) {
  const [sorting, setSorting] = React.useState<SortingState>([])
  const [columnFilters, setColumnFilters] = React.useState<ColumnFiltersState>([])
  const [columnVisibility, setColumnVisibility] = React.useState<VisibilityState>({ email: false, contact: false })
  const [rowSelection, setRowSelection] = React.useState({})

  const upcomingBookings = React.useMemo(() => {
    return bookings
      .filter((b) => b.status === "Pending")
      .sort((a, b) => a.date.getTime() - b.date.getTime());
  }, [bookings])

  const table = useReactTable({
    data: upcomingBookings,
    columns,
    onSortingChange: setSorting,
    onColumnFiltersChange: setColumnFilters,
    getCoreRowModel: getCoreRowModel(),
    getSortedRowModel: getSortedRowModel(),
    getFilteredRowModel: getFilteredRowModel(),
    onColumnVisibilityChange: setColumnVisibility,
    onRowSelectionChange: setRowSelection,
    state: { sorting, columnFilters, columnVisibility, rowSelection },
  })

  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center justify-between gap-2">
          <div className="flex items-center gap-2">
            <IconCalendarClock className="size-4 text-blue-500" />
            <h1 className="bg-gradient-to-r from-[#3F51B5] via-[#3A79C3] to-[#329A9A] bg-clip-text text-base font-bold text-transparent">
              Upcoming Bookings
            </h1>
          </div>
          <Link href="/admin/bookings" className="text-sm font-medium text-[#3A79C3] hover:underline">
            View All
          </Link>
        </CardTitle>
      </CardHeader>
      <CardContent className="px-4">
        <div className="overflow-hidden rounded-md border">
          <Table>
            <TableHeader>
              {table.getHeaderGroups().map((headerGroup) => (
                <TableRow key={headerGroup.id}>
                  {headerGroup.headers.map((header) => (
                    <TableHead key={header.id}>
                      {header.isPlaceholder ? null : flexRender(header.column.columnDef.header, header.getContext())}
                    </TableHead>
                  ))}
                </TableRow>
              ))}
            </TableHeader>
            <TableBody>
              {table.getRowModel().rows?.length ? (
                table.getRowModel().rows.map((row) => (
                  <TableRow key={row.id} data-state={row.getIsSelected() && "selected"}>
                    {row.getVisibleCells().map((cell) => (
                      <TableCell key={cell.id}>
                        {flexRender(cell.column.columnDef.cell, cell.getContext())}
                      </TableCell>
                    ))}
                  </TableRow>
                ))
              ) : (
                <TableRow>
                  <TableCell colSpan={columns.length} className="h-24 text-center">
                    No upcoming bookings.
                  </TableCell>
                </TableRow>
              )}
            </TableBody>
          </Table>
        </div>
      </CardContent>
    </Card>
  )
}

import { MOCK_BOOKED_DATES, MOCK_BOOKED_SLOTS, MOCK_BOOKINGS } from "../mock-data";
import { Booking } from "../schemas";

// Simulate network latency
const delay = (ms: number) => new Promise((resolve) => setTimeout(resolve, ms));

export async function getBookedSlots(date: Date): Promise<string[]> {
  await delay(300); // 300ms network delay simulation
  // In a real app, this would query the DB for slots that intersect with the given day
  return MOCK_BOOKED_SLOTS;
}

export async function getFullyBookedDates(): Promise<Date[]> {
  await delay(300);
  return MOCK_BOOKED_DATES;
}

export async function getAllBookings(): Promise<Booking[]> {
  await delay(500);
  return MOCK_BOOKINGS;
}
